// Self-checking TB for mlp_xor, generated by mlp_gen.py.
`timescale 1ns/1ps
module tb_mlp_xor;
    reg clk = 0, rst = 1;
    reg  signed [2*8-1:0] x_flat;
    wire signed [1*8-1:0] y_flat;
    integer errors = 0, t;
    mlp_xor dut (.clk(clk), .rst(rst), .x_flat(x_flat), .y_flat(y_flat));
    always #5 clk = ~clk;
    initial begin
        $dumpfile("wave.vcd"); $dumpvars(0, tb_mlp_xor);
        repeat (2) @(negedge clk); rst = 0;
        @(negedge clk); x_flat = 16'h0000;
        repeat (2) @(negedge clk); #1;   // pipeline fill
        if ($signed(y_flat[0*8 +: 8]) !== (-8'sd86)) begin errors=errors+1; $display("FAIL t0 out0: got %0d want -86", $signed(y_flat[0*8 +: 8])); end
        @(negedge clk); x_flat = 16'h1000;
        repeat (2) @(negedge clk); #1;   // pipeline fill
        if ($signed(y_flat[0*8 +: 8]) !== (8'sd72)) begin errors=errors+1; $display("FAIL t1 out0: got %0d want 72", $signed(y_flat[0*8 +: 8])); end
        @(negedge clk); x_flat = 16'h0010;
        repeat (2) @(negedge clk); #1;   // pipeline fill
        if ($signed(y_flat[0*8 +: 8]) !== (8'sd84)) begin errors=errors+1; $display("FAIL t2 out0: got %0d want 84", $signed(y_flat[0*8 +: 8])); end
        @(negedge clk); x_flat = 16'h1010;
        repeat (2) @(negedge clk); #1;   // pipeline fill
        if ($signed(y_flat[0*8 +: 8]) !== (-8'sd88)) begin errors=errors+1; $display("FAIL t3 out0: got %0d want -88", $signed(y_flat[0*8 +: 8])); end
        @(negedge clk); x_flat = 16'h0808;
        repeat (2) @(negedge clk); #1;   // pipeline fill
        if ($signed(y_flat[0*8 +: 8]) !== (8'sd72)) begin errors=errors+1; $display("FAIL t4 out0: got %0d want 72", $signed(y_flat[0*8 +: 8])); end
        @(negedge clk); x_flat = 16'h0810;
        repeat (2) @(negedge clk); #1;   // pipeline fill
        if ($signed(y_flat[0*8 +: 8]) !== (-8'sd2)) begin errors=errors+1; $display("FAIL t5 out0: got %0d want -2", $signed(y_flat[0*8 +: 8])); end
        if (errors == 0) $display("TB PASS: mlp_xor");
        else $display("TB FAIL: mlp_xor (%0d errors)", errors);
        $finish;
    end
endmodule
